WITH all_schemas AS (SELECT n.oid AS object_id, n.nspname AS object_schema, PG_GET_USERBYID(n.nspowner) AS schema_owner, CASE WHEN NOT n.nspname ~ '^pg_' AND (n.nspname <> ALL(ARRAY['pg_catalog', 'information_schema'])) THEN FALSE ELSE TRUE END AS system_object FROM pg_namespace AS n), all_tables AS (SELECT c.relnamespace AS object_id, COUNT(*) AS table_count FROM pg_class AS c WHERE c.relkind = ANY(ARRAY['r', 'p']) GROUP BY c.relnamespace), all_functions AS (SELECT p.pronamespace AS object_id, COUNT(*) AS function_count FROM pg_proc AS p GROUP BY p.pronamespace), all_views AS (SELECT c.relnamespace AS object_id, COUNT(*) AS view_count FROM pg_class AS c WHERE c.relkind = ANY(ARRAY['v', 'm']) GROUP BY c.relnamespace) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, s.object_schema, s.schema_owner, s.system_object, COALESCE(t.table_count, 0) AS table_count, COALESCE(v.view_count, 0) AS view_count, COALESCE(f.function_count, 0) AS function_count, 0 AS table_data_size_bytes, 0 AS total_table_size_bytes, CHR(34) || CURRENT_DATABASE() || CHR(34) AS database_name FROM all_schemas AS s LEFT JOIN all_tables AS t ON (s.object_id = t.object_id) LEFT JOIN all_views AS v ON (s.object_id = v.object_id) LEFT JOIN all_functions AS f ON (s.object_id = f.object_id)